class Solution {
    public int binaryGap(int n) {
        int maxGap = 0;
        int prevOne = 0;
        while (n > 0) {
            int lastBit = n & 1;
            n >>= 1;
            if (lastBit == 1) {
                maxGap = Math.max(maxGap, prevOne > 0 ? prevOne : 0);
                prevOne = 1;
            } else {
                prevOne = 0;
            }
        }
        return maxGap;
    }
}
